INSERT INTO programs (
  id, title, description, status, is_active, sort_order, metadata, target_age_min, target_age_max, difficulty_categories, learning_goals, skill_tags, level, access_type
) VALUES
  ('50a7b092-1867-5351-8cb5-10c8d2665e80', 'Toán và tư duy nền tảng', 'Các bài học đếm số, so sánh, nhận biết hình dạng và suy luận logic đơn giản cho trẻ 2-6 tuổi.', 'PUBLISHED', true, 10, '{"source":"seed_content_from_data_template","lessonTypes":["MATH","THINKING"],"expanded":false}'::jsonb, 2, 6, '["COGNITIVE_DELAY","ATTENTION_DIFFICULTY"]'::jsonb, '["COUNTING","MATCHING","OBJECT_RECOGNITION","FOLLOW_INSTRUCTION"]'::jsonb, '["COUNTING","MATCHING","OBJECT_RECOGNITION","FOLLOW_INSTRUCTION"]'::jsonb, 'BEGINNER', 'FREE'),
  ('eeb0299c-5b5e-52ca-b20a-f9a3392a3364', 'Giao tiếp và cảm xúc hằng ngày', 'Nội dung hội thoại giúp trẻ luyện chào hỏi, gọi tên con vật, cảm xúc và các mẫu câu lịch sự.', 'PUBLISHED', true, 20, '{"source":"seed_content_from_data_template","lessonTypes":["DIALOGUE"],"expanded":false}'::jsonb, 2, 6, '["SPEECH_DELAY","SOCIAL_COMMUNICATION","EMOTION_RECOGNITION"]'::jsonb, '["LISTENING","SPEAKING","DAILY_COMMUNICATION","EMOTION_RECOGNITION"]'::jsonb, '["LISTENING","SPEAKING","DAILY_COMMUNICATION","EMOTION_RECOGNITION"]'::jsonb, 'BEGINNER', 'FREE'),
  ('2c325972-efba-5299-90f6-7fb88b8ef13f', 'Từ vựng trực quan qua thẻ', 'Bộ flashcard về gia đình, màu sắc, phương tiện và đồ vật quen thuộc để trẻ học qua hình ảnh.', 'PUBLISHED', true, 30, '{"source":"seed_content_from_data_template","lessonTypes":["FLASHCARD"],"expanded":false}'::jsonb, 2, 6, '["SPEECH_DELAY","COGNITIVE_DELAY"]'::jsonb, '["OBJECT_RECOGNITION","LISTENING","SPEAKING"]'::jsonb, '["OBJECT_RECOGNITION","LISTENING","SPEAKING"]'::jsonb, 'BEGINNER', 'FREE'),
  ('75ce60b5-09de-5fc1-be48-4932e8ae4f7e', 'Tiếng Việt âm chữ vần', 'Các bài nhận biết chữ cái, ghép âm đầu và luyện vần đơn giản.', 'PUBLISHED', true, 40, '{"source":"seed_content_from_data_template","lessonTypes":["SPELLING","RHYME"],"expanded":false}'::jsonb, 2, 6, '["SPEECH_DELAY","COGNITIVE_DELAY"]'::jsonb, '["LISTENING","SPEAKING","OBJECT_RECOGNITION"]'::jsonb, '["LISTENING","SPEAKING","OBJECT_RECOGNITION"]'::jsonb, 'BEGINNER', 'FREE'),
  ('009a4d8d-3881-57d9-9e19-6b734e49def4', 'Toán hình ảnh mở rộng', 'Tăng số lượng bài luyện đếm, so sánh, ghép nhóm và nhận ra quy luật qua hình ảnh.', 'PUBLISHED', true, 50, '{"source":"seed_content_from_data_template","lessonTypes":["MATH","THINKING"],"expanded":true}'::jsonb, 2, 6, '["COGNITIVE_DELAY","ATTENTION_DIFFICULTY"]'::jsonb, '["COUNTING","MATCHING","OBJECT_RECOGNITION","FOLLOW_INSTRUCTION"]'::jsonb, '["COUNTING","MATCHING","OBJECT_RECOGNITION"]'::jsonb, 'BEGINNER', 'FREE'),
  ('81808b00-5ac6-5342-8b05-71004ee1e23e', 'Giao tiếp ở nhà và lớp học', 'Các tình huống nói lời phù hợp với cô giáo, bạn bè và người thân.', 'PUBLISHED', true, 60, '{"source":"seed_content_from_data_template","lessonTypes":["DIALOGUE","FLASHCARD"],"expanded":true}'::jsonb, 2, 6, '["SPEECH_DELAY","SOCIAL_COMMUNICATION"]'::jsonb, '["LISTENING","SPEAKING","DAILY_COMMUNICATION"]'::jsonb, '["LISTENING","SPEAKING","DAILY_COMMUNICATION"]'::jsonb, 'BEGINNER', 'FREE'),
  ('183c1b89-ed6c-5500-aa5e-405327f23881', 'Cảm xúc và tự chăm sóc', 'Giúp trẻ nhận biết cảm xúc, chọn phản ứng phù hợp và thực hành thói quen tự chăm sóc.', 'PUBLISHED', true, 70, '{"source":"seed_content_from_data_template","lessonTypes":["DIALOGUE","THINKING"],"expanded":true}'::jsonb, 2, 6, '["EMOTION_RECOGNITION","DAILY_LIFE_SKILL"]'::jsonb, '["EMOTION_RECOGNITION","DAILY_COMMUNICATION","FOLLOW_INSTRUCTION"]'::jsonb, '["EMOTION_RECOGNITION","DAILY_COMMUNICATION","FOLLOW_INSTRUCTION"]'::jsonb, 'BEGINNER', 'FREE'),
  ('a4b532a5-b1b8-5eb9-860d-f60bfb0fccde', 'Thế giới quanh em', 'Mở rộng vốn từ và hiểu biết về trái cây, phương tiện, thời tiết, đồ vật và thiên nhiên.', 'PUBLISHED', true, 80, '{"source":"seed_content_from_data_template","lessonTypes":["FLASHCARD","MATH","THINKING"],"expanded":true}'::jsonb, 2, 6, '["COGNITIVE_DELAY","ATTENTION_DIFFICULTY"]'::jsonb, '["OBJECT_RECOGNITION","COUNTING","MATCHING"]'::jsonb, '["OBJECT_RECOGNITION","COUNTING","MATCHING"]'::jsonb, 'BEGINNER', 'FREE'),
  ('f9da4684-2c53-54fe-967a-1b006cb0d2bc', 'Tiếng Việt mở rộng', 'Thêm nhiều bài nhận biết âm đầu, chữ còn thiếu và vần thông dụng.', 'PUBLISHED', true, 90, '{"source":"seed_content_from_data_template","lessonTypes":["SPELLING","RHYME"],"expanded":true}'::jsonb, 2, 6, '["SPEECH_DELAY","COGNITIVE_DELAY"]'::jsonb, '["LISTENING","SPEAKING","OBJECT_RECOGNITION"]'::jsonb, '["LISTENING","SPEAKING","OBJECT_RECOGNITION"]'::jsonb, 'BEGINNER', 'FREE'),
  ('608f5ed2-e1e0-5b31-b85d-a860d14e69d7', 'Trò chơi tư duy logic', 'Các câu hỏi tìm khác biệt, dự đoán kết quả, chọn bước tiếp theo và nhận ra quy tắc.', 'PUBLISHED', true, 100, '{"source":"seed_content_from_data_template","lessonTypes":["THINKING","MATH"],"expanded":true}'::jsonb, 2, 6, '["COGNITIVE_DELAY","ATTENTION_DIFFICULTY"]'::jsonb, '["FOLLOW_INSTRUCTION","MATCHING","COUNTING"]'::jsonb, '["FOLLOW_INSTRUCTION","MATCHING","COUNTING"]'::jsonb, 'BEGINNER', 'FREE'),
  ('32e5e704-1126-5720-a385-c3aac99c5aa1', 'Flashcard theo chủ đề', 'Bộ thẻ ghi nhớ mở rộng cho nhiều nhóm từ gần gũi trong sinh hoạt.', 'PUBLISHED', true, 110, '{"source":"seed_content_from_data_template","lessonTypes":["FLASHCARD"],"expanded":true}'::jsonb, 2, 6, '["SPEECH_DELAY","COGNITIVE_DELAY"]'::jsonb, '["OBJECT_RECOGNITION","LISTENING","SPEAKING"]'::jsonb, '["OBJECT_RECOGNITION","LISTENING","SPEAKING"]'::jsonb, 'BEGINNER', 'FREE'),
  ('aa95cdf1-e963-5434-980e-e7ea79f70cda', 'Nghe hiểu và làm theo chỉ dẫn', 'Luyện nghe tình huống, chọn câu trả lời và làm theo yêu cầu ngắn.', 'PUBLISHED', true, 120, '{"source":"seed_content_from_data_template","lessonTypes":["DIALOGUE","THINKING"],"expanded":true}'::jsonb, 2, 6, '["SPEECH_DELAY","ATTENTION_DIFFICULTY","SOCIAL_COMMUNICATION"]'::jsonb, '["LISTENING","FOLLOW_INSTRUCTION","DAILY_COMMUNICATION"]'::jsonb, '["LISTENING","FOLLOW_INSTRUCTION","DAILY_COMMUNICATION"]'::jsonb, 'BEGINNER', 'FREE')
